/// ECMA-376 §17.13.6.2; MS-OI29500 §2.1.356; ECMA-376 §17.13.2.
///
/// A bookmarkStart whose w:name exceeds Word's 40-char limit is preserved
/// verbatim through reserialization: the 40-char cap is a Word load-time
/// behaviour, not a markup the serializer should rewrite. The standard allows
/// any-length names on disk and stemma round-trips untouched content verbatim.
#[test]
fn bookmark_name_over_40_chars_survives_reserialize_verbatim() {
    let body = r#"<w:p><w:bookmarkStart w:id="0" w:name="thisBookmarkNameIsDeliberatelyLongerThanFortyCharacters"/><w:r><w:t>Seattle</w:t></w:r><w:bookmarkEnd w:id="0"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains("thisBookmarkNameIsDeliberatelyLongerThanFortyCharacters"),
        "MS-OI29500 §2.1.356 (refs: ECMA-376 §17.13.6.2, §17.13.2): the 40-char cap is Word's \
         load-time limit; the standard allows any-length names on disk and stemma preserves \
         untouched content verbatim, so the full bookmark name must survive reserialization. \
         Re-serialized document.xml:\n{xml}"
    );
    assert!(
        xml.contains("w:bookmarkEnd"),
        "ECMA-376 §17.13.6.1/.2: a bookmarkStart requires a paired bookmarkEnd with the same \
         id; the serializer must re-emit the end marker so the pair stays balanced. \
         Re-serialized document.xml:\n{xml}"
    );
}

/// ECMA-376 §17.13.7.2; MS-OI29500 §2.1.358; ECMA-376 §17.13.2.
///
/// A balanced permStart/permEnd pair carrying both ed and edGrp opens clean and
/// is zero-width: ed-over-edGrp is a read-time decision, never a save-time
/// rewrite, and the markers contribute no text.
#[test]
fn permstart_ed_and_edgrp_consumption_uses_ed_opens_clean_zero_width() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">This is a </w:t></w:r><w:permStart w:id="0" w:ed="DOMAIN\user" w:edGrp="everyone"/><w:r><w:t>range permission</w:t></w:r><w:permEnd w:id="0"/><w:r><w:t>.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.13.7.2 / MS-OI29500 §2.1.358: a balanced permStart/permEnd carrying ed \
         (and edGrp) is conformant; ed-over-edGrp is a read-time decision, not a save error, so \
         validate() must report no errors. Issues: {detail}"
    );

    assert_eq!(
        accept_text(&b),
        "This is a range permission.",
        "ECMA-376 §17.13.2: permStart/permEnd are zero-width markers ('do not contain it'); \
         accept-all yields the concatenated run text only."
    );
}

/// ECMA-376 §17.13.4.4; MS-OI29500 §2.1.315; ECMA-376 §17.13.2.
///
/// A commentRangeStart with no corresponding commentRangeEnd is a single
/// zero-width anchor point (Word anchors at the commentReference). It
/// contributes no text to any read projection.
#[test]
fn lone_comment_range_start_is_zero_width_anchor() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Some </w:t></w:r><w:commentRangeStart w:id="0"/><w:r><w:t>text.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "Some text.",
        "MS-OI29500 §2.1.315 / ECMA-376 §17.13.2: a lone commentRangeStart is a zero-width \
         single anchor and contains no content, so accepted text is exactly the two runs \
         concatenated."
    );
    assert_eq!(
        reject_text(&b),
        "Some text.",
        "ECMA-376 §17.13.2: a comment marker is an annotation, not a tracked change, so \
         rejecting changes nothing and the marker still contributes no text."
    );
}

/// ECMA-376 §17.13.6.2; MS-OI29500 §2.1.356; ECMA-376 §17.13.2.
///
/// A table bookmark whose colFirst exceeds colLast opens clean: Word clamps
/// colFirst to colLast (read-time adjustment) and the markers stay zero-width.
#[test]
fn table_bookmark_colfirst_gt_collast_opens_clean_zero_text() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/><w:gridCol w:w="2000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:bookmarkStart w:id="0" w:name="tbm" w:colFirst="3" w:colLast="1"/><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>C</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>D</w:t></w:r></w:p></w:tc><w:bookmarkEnd w:id="0"/></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "MS-OI29500 §2.1.356 (refs: ECMA-376 §17.13.6.2, §17.13.2): Word clamps colFirst to \
         colLast and opens the file; therefore validate() must report no errors (would-be Word \
         repair). Issues: {detail}"
    );
}

/// ECMA-376 §17.13.7.2; MS-OI29500 §2.1.358; ECMA-376 §17.13.2.
///
/// A column-scoped table range permission whose colFirst/colLast exceed the
/// table's column count opens clean: Word does not reject the file (it behaves
/// unpredictably at read time but still opens).
#[test]
fn perm_colfirst_collast_exceed_table_columns_opens_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/><w:gridCol w:w="2000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:permStart w:id="0" w:edGrp="everyone" w:colFirst="5" w:colLast="9"/><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>C</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>D</w:t></w:r></w:p></w:tc><w:permEnd w:id="0"/></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "MS-OI29500 §2.1.358 (refs: ECMA-376 §17.13.7.2, §17.13.2): Word does not reject \
         out-of-range colFirst/colLast on a perm; it opens (behaving unpredictably). validate() \
         must report no errors. Issues: {detail}"
    );
}

/// ECMA-376 §17.13.7.2; ECMA-376 §17.13.2.
///
/// A permStart carrying both colFirst and colLast (col pair complete) that is
/// NOT in a table has its column values ignored; the document is conformant,
/// opens clean, and the markers contribute no text.
#[test]
fn perm_colfirst_collast_outside_table_ignored_opens_clean() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">This is a </w:t></w:r><w:permStart w:id="0" w:edGrp="everyone" w:colFirst="0" w:colLast="1"/><w:r><w:t>range permission</w:t></w:r><w:permEnd w:id="0"/><w:r><w:t>.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.13.7.2: col values on a non-table perm are ignored, not invalid (and \
         colLast is present so the both-or-neither pairing rule holds); validate() must report \
         no errors. Issues: {detail}"
    );
    assert_eq!(
        accept_text(&b),
        "This is a range permission.",
        "ECMA-376 §17.13.2: permStart/permEnd are zero-width markers; accepted text is exactly \
         the three runs concatenated."
    );
}

/// ECMA-376 §17.13.4.4, §17.13.4.3, §17.13.2.
///
/// A commentRangeStart/End pair whose start is in one paragraph and end in the
/// next is a valid cross-structure annotation: the markers are zero-width and
/// contribute no text, so reading concatenates per-paragraph run text with the
/// normal block separator.
#[test]
fn cross_paragraph_comment_range_markers_zero_width() {
    let body = r#"<w:p><w:r><w:t>Example</w:t></w:r><w:commentRangeStart w:id="0"/><w:r><w:t xml:space="preserve"> one</w:t></w:r></w:p><w:p><w:r><w:t>Example</w:t></w:r><w:commentRangeEnd w:id="0"/><w:r><w:t xml:space="preserve"> two</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "Example one\n\nExample two",
        "ECMA-376 §17.13.2 (refs: §17.13.4.3/.4): the cross-paragraph commentRangeStart/End \
         markers contain no content, so accepted text is the two paragraphs' runs joined by the \
         block separator (\\n\\n)."
    );
    assert_eq!(
        reject_text(&b),
        "Example one\n\nExample two",
        "ECMA-376 §17.13.2: comment range markers are annotations, not tracked changes; \
         rejecting does not alter them and they still contribute no text."
    );
}

/// ISO 29500-1 §17.13.4.4; MS-OI29500 §2.1.315; ECMA-376 §17.13.2.
///
/// A commentRangeStart with no matching commentRangeEnd is NOT non-conformant
/// to Word: Word opens the file clean and uses the commentReference as the
/// single anchor point, so validate() must report no errors. A failure means
/// stemma's I-ANN-005 pairing check is stricter than Word.
#[test]
fn lone_comment_range_start_opens_clean() {
    let body = r#"<w:p><w:r><w:t>Before </w:t></w:r><w:commentRangeStart w:id="1"/><w:r><w:t>anchored text</w:t></w:r><w:r><w:rPr><w:rStyle w:val="CommentReference"/></w:rPr><w:commentReference w:id="1"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "MS-OI29500 §2.1.315 (refs: ISO 29500-1 §17.13.4.4, ECMA-376 §17.13.2): Word opens a \
         lone commentRangeStart by anchoring at the commentReference; it is not an open-blocking \
         error, so validate() must report no errors. A failure means stemma's I-ANN-005 pairing \
         check is stricter than Word. Issues: {detail}"
    );
}

