/// ISO 29500-1 §17.13.4.3/.4; MS-OI29500 §2.1.314/.315.
///
/// commentRange/commentReference markers are zero-width annotations, never
/// tracked changes, so accepting or rejecting all changes leaves the run text
/// exactly as authored even when a marker is unpaired.
#[ignore = "open question: read projection emits a U+FFFC object-replacement char for the \
            commentReference run, so comment anchors are not zero-width in read_accepted/to_text \
            (ISO 29500-1 §17.13.4 / ECMA §17.13.2)"]
#[test]
fn lone_comment_range_markers_contribute_no_text() {
    let body = r#"<w:p><w:r><w:t>anchored text</w:t></w:r><w:commentRangeEnd w:id="1"/><w:r><w:rPr><w:rStyle w:val="CommentReference"/></w:rPr><w:commentReference w:id="1"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "anchored text",
        "ISO 29500-1 §17.13.4: comment markers are zero-width annotations; accept-all does not \
         touch run text, so accepted text equals the authored run text."
    );
    assert_eq!(
        reject_text(&b),
        "anchored text",
        "ISO 29500-1 §17.13.4: comment markers are not tracked changes; reject-all does not \
         touch run text, so rejected text equals the authored run text."
    );
}

/// ECMA-376 / ISO 29500-1 §17.13.4.4 (mirror §17.13.4.3, §17.13.4.5).
///
/// A balanced commentRangeStart/End pair with NO commentReference of the same
/// id anywhere in the document story is non-conformant; the document must be
/// flagged, not silently opened clean. (INVERTED post-condition: opens_clean
/// must be FALSE. If it is true, stemma's pairing check does not verify
/// reference presence — the gap this test hunts.)
#[ignore = "open question: stemma annotation pairing (I-ANN-005) verifies start<->end only, not \
            commentReference presence; a torn comment Word cannot link is accepted clean \
            (ECMA-376/ISO 29500-1 §17.13.4.4, mirror §17.13.4.3/.4.5)"]
#[test]
fn comment_range_pair_without_reference_is_nonconformant() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Some </w:t></w:r><w:commentRangeStart w:id="0"/><w:r><w:t>text</w:t></w:r><w:commentRangeEnd w:id="0"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        !ok,
        "ECMA-376 / ISO 29500-1 §17.13.4.4 (mirror §17.13.4.3, §17.13.4.5): a \
         commentRangeStart/End pair with NO matching commentReference is non-conformant ('then \
         the document is non-conformant'); a Word-faithful validator must report an error, so \
         validate() should NOT be clean. It reported clean — stemma's annotation pairing check \
         does not verify reference presence. Issues: {detail}"
    );
}

/// ECMA-376 / ISO 29500-1 §17.13.6.1; ECMA-376 §17.13.2.
///
/// A bookmarkEnd with no bookmarkStart of the same id appearing PRIOR to it in
/// document order is non-conformant — even if a bookmarkStart with that id
/// appears later. (INVERTED post-condition: opens_clean must be FALSE. If
/// stemma pairs purely by id ignoring relative order it reports clean — the gap
/// this test hunts.)
#[ignore = "open question: stemma bookmark pairing (I-ANN-003) matches start<->end by id count and \
            does not enforce start-before-end document order; a reversed pair passes clean \
            (ECMA-376/ISO 29500-1 §17.13.6.1)"]
#[test]
fn bookmarkend_before_bookmarkstart_in_document_order_is_nonconformant() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">a </w:t></w:r><w:bookmarkEnd w:id="0"/><w:r><w:t xml:space="preserve">b </w:t></w:r><w:bookmarkStart w:id="0" w:name="reversed"/><w:r><w:t>c</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        !ok,
        "ECMA-376 / ISO 29500-1 §17.13.6.1 (refs: §17.13.2): a bookmarkEnd with no matching \
         bookmarkStart strictly prior in document order is non-conformant ('then the document is \
         non-conformant'); a Word-faithful validator must report an error, so validate() should \
         NOT be clean. It reported clean — stemma pairs by id without enforcing start-before-end \
         order. Issues: {detail}"
    );
}
